const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    positive: '#10b981',
    negative: '#f43f5e',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
    orange: '#fb923c',
  },
  font: "'JetBrains Mono', monospace",
};

// ============================================
// Linear Regression Calculation
// ============================================
function computeRegression(X, y) {
  const m = X.length;
  const n = X[0].length;

  const Xt = [];
  for (let j = 0; j < n; j++) {
    Xt.push(X.map(row => row[j]));
  }

  const XtX = [];
  for (let i = 0; i < n; i++) {
    XtX.push([]);
    for (let j = 0; j < n; j++) {
      let sum = 0;
      for (let k = 0; k < m; k++) {
        sum += Xt[i][k] * X[k][j];
      }
      XtX[i].push(sum);
    }
  }

  const Xty = [];
  for (let i = 0; i < n; i++) {
    let sum = 0;
    for (let k = 0; k < m; k++) {
      sum += Xt[i][k] * y[k];
    }
    Xty.push(sum);
  }

  const det = XtX[0][0] * XtX[1][1] - XtX[0][1] * XtX[1][0];
  const XtXinv = [
    [XtX[1][1] / det, -XtX[0][1] / det],
    [-XtX[1][0] / det, XtX[0][0] / det]
  ];

  const theta = [];
  for (let i = 0; i < n; i++) {
    let sum = 0;
    for (let j = 0; j < n; j++) {
      sum += XtXinv[i][j] * Xty[j];
    }
    theta.push(Math.round(sum * 10000) / 10000);
  }

  return { Xt, XtX, Xty, XtXinv, theta, det };
}

// ============================================
// Scatter Plot with Regression Line
// ============================================
function RegressionPlot({ points, theta, step }) {
  const canvasRef = useRef(null);
  const size = 220;
  const padding = 35;

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');

    ctx.fillStyle = theme.colors.surface;
    ctx.fillRect(0, 0, size, size);

    const xVals = points.map(p => p.x);
    const yVals = points.map(p => p.y);

    const xMin = Math.min(...xVals) - 0.5;
    const xMax = Math.max(...xVals) + 0.5;
    const yMin = Math.min(...yVals, 0) - 0.5;
    const yMax = Math.max(...yVals) + 1;

    const scaleX = (x) => padding + ((x - xMin) / (xMax - xMin)) * (size - 2 * padding);
    const scaleY = (y) => size - padding - ((y - yMin) / (yMax - yMin)) * (size - 2 * padding);

    // Grid
    ctx.strokeStyle = theme.colors.border;
    ctx.lineWidth = 1;
    for (let i = 0; i <= 4; i++) {
      const x = padding + (i / 4) * (size - 2 * padding);
      const y = padding + (i / 4) * (size - 2 * padding);
      ctx.beginPath();
      ctx.moveTo(x, padding);
      ctx.lineTo(x, size - padding);
      ctx.stroke();
      ctx.beginPath();
      ctx.moveTo(padding, y);
      ctx.lineTo(size - padding, y);
      ctx.stroke();
    }

    // Axes
    ctx.strokeStyle = theme.colors.textMuted;
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(padding, size - padding);
    ctx.lineTo(size - padding, size - padding);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(padding, padding);
    ctx.lineTo(padding, size - padding);
    ctx.stroke();

    // Axis labels
    ctx.fillStyle = theme.colors.textMuted;
    ctx.font = '10px JetBrains Mono';
    ctx.textAlign = 'center';
    ctx.fillText('x', size / 2, size - 8);
    ctx.save();
    ctx.translate(10, size / 2);
    ctx.rotate(-Math.PI / 2);
    ctx.fillText('y', 0, 0);
    ctx.restore();

    // Show residuals at step 5+
    if (step >= 5 && theta) {
      points.forEach((p) => {
        const predicted = theta[0] + theta[1] * p.x;
        ctx.strokeStyle = theme.colors.negative;
        ctx.lineWidth = 2;
        ctx.setLineDash([4, 4]);
        ctx.beginPath();
        ctx.moveTo(scaleX(p.x), scaleY(p.y));
        ctx.lineTo(scaleX(p.x), scaleY(predicted));
        ctx.stroke();
        ctx.setLineDash([]);
      });
    }

    // Regression line at step 6
    if (step >= 6 && theta) {
      const x1 = xMin;
      const x2 = xMax;
      const y1 = theta[0] + theta[1] * x1;
      const y2 = theta[0] + theta[1] * x2;

      ctx.strokeStyle = theme.colors.positive;
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.moveTo(scaleX(x1), scaleY(y1));
      ctx.lineTo(scaleX(x2), scaleY(y2));
      ctx.stroke();
    }

    // Points
    points.forEach((p, i) => {
      ctx.fillStyle = step >= 1 ? theme.colors.blue : theme.colors.textMuted;
      ctx.beginPath();
      ctx.arc(scaleX(p.x), scaleY(p.y), 7, 0, Math.PI * 2);
      ctx.fill();
      ctx.strokeStyle = theme.colors.text;
      ctx.lineWidth = 2;
      ctx.stroke();
    });

  }, [points, theta, step]);

  return (
    <canvas
      ref={canvasRef}
      width={size}
      height={size}
      style={{ borderRadius: '8px', display: 'block' }}
    />
  );
}

