function Matrix({ data, label, color, highlight, small }) {
  const isVector = !Array.isArray(data[0]);
  const rows = isVector ? data.map(v => [v]) : data;
  const cellSize = small ? '24px' : '32px';
  const fontSize = small ? '10px' : '12px';

  return (
    <div style={{ textAlign: 'center' }}>
      {label && (
        <div style={{ fontSize: '9px', color: theme.colors.textMuted, marginBottom: '3px' }}>
          {label}
        </div>
      )}
      <div style={{
        display: 'inline-flex',
        alignItems: 'center',
        padding: '4px',
        background: highlight ? `${color}15` : theme.colors.surface,
        borderRadius: '6px',
        border: `2px solid ${highlight ? color : theme.colors.border}`,
        transition: 'all 0.3s',
      }}>
        <span style={{ color: color || theme.colors.textMuted, fontSize: small ? '20px' : '28px', fontWeight: '200' }}>[</span>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1px' }}>
          {rows.map((row, i) => (
            <div key={i} style={{ display: 'flex', gap: '2px' }}>
              {row.map((val, j) => (
                <div
                  key={j}
                  style={{
                    width: cellSize,
                    height: cellSize,
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontSize,
                    fontWeight: '600',
                    color: theme.colors.text,
                  }}
                >
                  {typeof val === 'number' ? (Number.isInteger(val) ? val : val.toFixed(2)) : val}
                </div>
              ))}
            </div>
          ))}
        </div>
        <span style={{ color: color || theme.colors.textMuted, fontSize: small ? '20px' : '28px', fontWeight: '200' }}>]</span>
      </div>
    </div>
  );
}

