      X: [[1, 1], [1, 2], [1, 3]],
      y: [1, 2, 3],
    },
    {
      name: 'With Noise',
      X: [[1, 1], [1, 2], [1, 3], [1, 4]],
      y: [1.2, 1.9, 3.1, 4.0],
    },
    {
      name: 'Negative Slope',
      X: [[1, 1], [1, 2], [1, 3]],
      y: [3, 2, 1],
    },
  ];

  const ex = examples[exampleIdx];
